export const meta = {
  name: 'issue-427-phaseB-design',
  description: 'Design & harden Phase B (Tier-2 whole-language detection) + ecosystem expansion for SKF shape-detect',
  phases: [
    { title: 'Map', detail: 'parallel readers map the real scanner/clone/dataflow architecture' },
    { title: 'Validate', detail: 'ground signal robustness against real language repos via deepwiki' },
    { title: 'Design', detail: 'competing architecture proposals for expansion + conjunction rule' },
    { title: 'Score', detail: 'judge panel scores the proposals' },
    { title: 'RedTeam', detail: 'adversarially attack the conjunction rule with false-positive candidates' },
    { title: 'Synthesize', detail: 'merge winner + graft best ideas + red-team fixes into one blueprint' },
  ],
}

const ROOT = '/home/armel/Projects/OSS/bmad-module-skill-forge'

const MAP_SCHEMA = {
  type: 'object',
  required: ['area', 'facts', 'seams', 'how_to_extend'],
  properties: {
    area: { type: 'string' },
    facts: {
      type: 'array',
      items: {
        type: 'object',
        required: ['claim', 'file', 'evidence'],
        properties: {
          claim: { type: 'string' },
          file: { type: 'string' },
          lines: { type: 'string' },
          evidence: { type: 'string', description: 'quoted code or exact value' },
        },
      },
    },
    seams: { type: 'array', items: { type: 'string' }, description: 'exact insertion points for expansion' },
    how_to_extend: { type: 'string' },
  },
}

const VALIDATE_SCHEMA = {
  type: 'object',
  required: ['repo', 'ecosystem', 'has_supported_manifest', 'reachable_today', 'recommended_signal', 'false_positive_risk', 'expected_classification'],
  properties: {
    repo: { type: 'string' },
    ecosystem: { type: 'string' },
    has_supported_manifest: { type: 'boolean', description: 'package.json / Cargo.toml / pyproject.toml present at a level SKF scans' },
    manifest_signals: { type: 'array', items: { type: 'string' } },
    tree_signals: { type: 'array', items: { type: 'string' }, description: 'grammar files, compiler/ or parser+lexer+ast dirs' },
    reachable_today: { type: 'boolean', description: 'does the repo even reach shape-detect today' },
    recommended_signal: { type: 'string', description: 'the single most robust signal that should catch (or reject) this repo' },
    false_positive_risk: { type: 'string', enum: ['none', 'low', 'medium', 'high'] },
    expected_classification: { type: 'string', description: 'language-reference | NOT-language-reference, and why' },
    grounded_by: { type: 'string', description: 'how the claim was verified (deepwiki/websearch/knowledge)' },
  },
}

const DESIGN_SCHEMA = {
  type: 'object',
  required: ['name', 'tier2_conjunction_rule', 'ecosystem_expansion', 'interface_change', 'files_touched', 'risks'],
  properties: {
    name: { type: 'string' },
    tier2_conjunction_rule: { type: 'string', description: 'precise rule for firing language-reference from tree/grammar signals without false positives' },
    ecosystem_expansion: {
      type: 'object',
      required: ['go_mod', 'c_grammar_path'],
      properties: {
        go_mod: { type: 'string', description: 'how go.mod repos get scanned + classified' },
        c_grammar_path: { type: 'string', description: 'how manifest-less C repos (cpython, ruby) get scanned via grammar files, without breaking the manifest-first flow' },
      },
    },
    interface_change: { type: 'string', description: 'exact new args/inputs to skf-shape-detect.py and how AN assembles them' },
    acquisition_change: { type: 'string', description: 'sparse-checkout globs / tree fetch changes and their cost/gating' },
    files_touched: { type: 'array', items: { type: 'string' } },
    risks: { type: 'array', items: { type: 'string' } },
    effort: { type: 'string' },
  },
}

const SCORE_SCHEMA = {
  type: 'object',
  required: ['design_name', 'robustness', 'simplicity', 'blast_radius', 'coverage', 'total', 'rationale'],
  properties: {
    design_name: { type: 'string' },
    robustness: { type: 'number', description: '0-10 false-positive resistance' },
    simplicity: { type: 'number', description: '0-10 minimal-blast-radius / boring-tech' },
    blast_radius: { type: 'number', description: '0-10 where 10 = smallest blast radius' },
    coverage: { type: 'number', description: '0-10 how many real language repos it catches' },
    total: { type: 'number' },
    rationale: { type: 'string' },
    best_idea_to_graft: { type: 'string' },
  },
}

const REDTEAM_SCHEMA = {
  type: 'object',
  required: ['candidate', 'breaks_rule', 'why'],
  properties: {
    candidate: { type: 'string', description: 'a real repo that might wrongly fire language-reference' },
    breaks_rule: { type: 'boolean', description: 'true if the proposed conjunction rule misclassifies it' },
    why: { type: 'string' },
    fix: { type: 'string', description: 'how to tighten the rule so it does not break' },
  },
}

// ---------------------------------------------------------------------------
// Phase 1+2: Map the codebase AND validate signals against real repos (independent → one barrier)
// ---------------------------------------------------------------------------
phase('Map')
log('Mapping scanner/clone/dataflow architecture and validating signals against real language repos')

const mapTasks = [
  {
    label: 'map:scanner',
    prompt: `Read ${ROOT}/src/shared/scripts/skf-scan-manifests.py in full. Report EXACTLY: (1) which manifest filenames/ecosystems it recognizes; (2) how it discovers manifests (tree walk? fixed glob? depth limits?); (3) the JSON output schema it emits (the keys downstream consumes); (4) how a NEW manifest type (e.g. go.mod) would be added — what functions/constants change. Quote the recognized-manifest list and the output-emitting code with line numbers. area="scanner".`,
  },
  {
    label: 'map:clone',
    prompt: `Read ${ROOT}/src/skf-analyze-source/references/step-auto-scope.md, focus on the §2 "Manifest Scan" / git clone --filter=blob:none --sparse-checkout block AND any §0 input-routing. Quote the EXACT sparse-checkout path patterns and the command sequence with line numbers. Explain how the sparse-checkout set is constructed (fixed list? variable?) and precisely where you'd add grammar-file globs (*.pest,*.lalrpop,*.y,*.g4,*.gram) or directory globs (**/compiler/**) or go.mod. area="clone".`,
  },
  {
    label: 'map:interface',
    prompt: `Read ${ROOT}/src/shared/scripts/skf-shape-detect.py CLI/argparse section AND grep the repo for how skf-shape-detect.py is invoked (the --manifests assembly). Report: (1) confirm it takes ONLY --repo-url and --manifests; quote the argparse + the invocation in step-auto-scope.md with line numbers; (2) search the ENTIRE src/ tree for ANY non-manifest scanning — os.walk, rglob, glob over source files, directory-structure heuristics, tree listing — does ANY capability to inspect a repo's dir tree or grammar files exist today? (3) what is the minimal interface change to feed directory-structure or grammar-file signals into shape-detect (a new --tree-paths / --grammar-files arg)? area="interface".`,
  },
  {
    label: 'map:precedent',
    prompt: `Search the ENTIRE ${ROOT} repo (src/, test/, docs/, schemas) for any mention or partial support of non-(npm/python/rust) ecosystems or grammar files: grep for 'go.mod', 'golang', 'gradle', 'build.gradle', 'CMakeLists', 'go ', '.gram', 'parse.y', 'yacc', 'bison', 'tree-sitter', 'ecosystem'. Report every real hit with file:line and a one-line meaning. Is there ANY prior art, TODO, or design note about ecosystem expansion? area="precedent".`,
  },
  {
    label: 'map:dataflow',
    prompt: `Trace the data flow in ${ROOT}: input project_paths → clone/scan (skf-scan-manifests) → manifest list → skf-shape-detect → shape→scope.type mapping (step-auto-scope.md §4) → brief. Read step-auto-scope.md §0-§4 and skf-scan-manifests.py output. Report: (1) the exact handoff at each step (what data shape passes); (2) CRITICALLY — what happens TODAY if a repo has NO supported manifest (does scan return empty? does the pipeline hard-halt, fall to interactive, or skip)? Quote the exit-code / empty-manifest handling with line numbers; (3) where exactly a "manifest-less language repo" (cpython/go) would need to slot in so it doesn't break the flow that assumes >=1 manifest. area="dataflow".`,
  },
]

const validateRepos = [
  { repo: 'rust-lang/rust', hint: 'Cargo workspace; compiler crates under compiler/rustc_*; hand-written parser (no pest dep)' },
  { repo: 'microsoft/TypeScript', hint: 'npm; name=typescript; bin tsc; src/compiler/{scanner,parser,binder,checker}.ts; hand-written' },
  { repo: 'python/cpython', hint: 'C; PEG grammar at Grammar/python.gram; no package.json/Cargo/pyproject SKF scans' },
  { repo: 'golang/go', hint: 'go.mod ecosystem; src/cmd/compile; src/go/{scanner,parser,ast}; unsupported manifest' },
  { repo: 'ruby/ruby', hint: 'C; parse.y yacc grammar; no supported manifest' },
  { repo: 'prettier/prettier', hint: 'NEGATIVE control — a formatter with parsers; must NOT be language-reference' },
  { repo: 'eslint/eslint', hint: 'NEGATIVE control — a linter; has espree parser dep; must NOT be language-reference' },
  { repo: 'babel/babel', hint: 'AMBIGUOUS — a JS compiler/transpiler with @babel/parser; decide & justify whether it SHOULD be language-reference' },
  { repo: 'denoland/deno', hint: 'AMBIGUOUS — a JS/TS runtime in Rust using SWC; decide & justify' },
]

const mapAndValidate = await parallel([
  ...mapTasks.map(t => () => agent(t.prompt, { label: t.label, phase: 'Map', schema: MAP_SCHEMA })),
  ...validateRepos.map(r => () => agent(
    `You are validating shape-detection signals for the repo ${r.repo} for SKF issue #427. Context: ${r.hint}.\n\n` +
    `SKF classifies a repo as "language-reference" (whole-language / language-tooling skill). Today it only scans repos that have package.json, Cargo.toml, or pyproject.toml, and only fires language-reference on parser-generator DEPENDENCIES or (newly) the repo's own name being a known parser tool.\n\n` +
    `GROUND YOUR ANSWER IN REALITY: use the deepwiki MCP tool (ask_question about "${r.repo}") and/or web search to verify the repo's actual build manifest and directory structure — do NOT guess. Load the deepwiki tool via ToolSearch (query "select:mcp__deepwiki__ask_question") if needed.\n\n` +
    `Determine: does it have a supported manifest at a scannable level? What MANIFEST signals (name, deps, bin)? What TREE signals (grammar files like .pest/.y/.gram/.g4, or a compiler/ dir, or a lexer+parser+ast directory triad)? Is it reachable by SKF today at all? What is the SINGLE most robust signal that should catch it (or, for negative controls, what proves it must be REJECTED)? Rate false-positive risk of that signal. State expected_classification (language-reference or NOT) and why. For AMBIGUOUS repos, make a firm call and justify it.`,
    { label: `validate:${r.repo.split('/').pop()}`, phase: 'Validate', schema: VALIDATE_SCHEMA }
  )),
])

const maps = mapAndValidate.slice(0, mapTasks.length).filter(Boolean)
const validations = mapAndValidate.slice(mapTasks.length).filter(Boolean)
log(`Collected ${maps.length} architecture maps and ${validations.length} repo validations`)

// Compact digests to feed downstream
const mapDigest = maps.map(m =>
  `### ${m.area}\nFACTS:\n${m.facts.map(f => `- ${f.claim} [${f.file}${f.lines ? ':' + f.lines : ''}] :: ${f.evidence}`).join('\n')}\nSEAMS: ${m.seams.join(' | ')}\nEXTEND: ${m.how_to_extend}`
).join('\n\n')

const validateDigest = validations.map(v =>
  `- ${v.repo} [${v.ecosystem}] manifest=${v.has_supported_manifest} reachable=${v.reachable_today} → ${v.expected_classification} | best signal: ${v.recommended_signal} (FP risk: ${v.false_positive_risk}) | tree: ${(v.tree_signals||[]).join(',')} | grounded: ${v.grounded_by}`
).join('\n')

// ---------------------------------------------------------------------------
// Phase 3: Three independent design proposals (judge panel)
// ---------------------------------------------------------------------------
phase('Design')
const designAngles = [
  { key: 'minimal-blast', angle: 'MINIMAL BLAST RADIUS: reuse existing mechanisms as much as possible, smallest diff, boring tech. Prefer extending skf-scan-manifests + sparse-checkout over new components. Accept slightly lower coverage for much lower risk.' },
  { key: 'max-coverage', angle: 'MAXIMUM COVERAGE: catch every language repo the user named (rust, TypeScript, cpython, go, ruby) even if it needs a new grammar-file scan path for manifest-less C repos. Optimize for the acceptance criteria being fully met.' },
  { key: 'robustness-first', angle: 'ROBUSTNESS FIRST: zero tolerance for false positives (a formatter/linter/markdown lib must never classify as a language). Design the conjunction rule and gating to be provably tight, even if it means a two-tier gated fetch and conservative coverage.' },
]

const designs = await parallel(designAngles.map(d => () => agent(
  `You are a system architect designing Phase B (Tier-2 whole-language detection) + ecosystem expansion for SKF issue #427.\n\n` +
  `DESIGN STANCE: ${d.angle}\n\n` +
  `## Architecture map (ground truth from the codebase)\n${mapDigest}\n\n` +
  `## Real-repo signal validation\n${validateDigest}\n\n` +
  `## What is already DONE (Tier 1, do not redesign): producer detection keys on a repo's own package name being a known parser-gen tool (pest, lalrpop, lark, peggy...). That catches parser LIBRARIES but NOT whole-language compilers (rust-lang/rust, TypeScript) which have no parser-gen dep and ordinary names.\n\n` +
  `## Your job: produce a concrete, buildable design for:\n` +
  `1. tier2_conjunction_rule — the precise rule that fires language-reference from TREE/grammar signals (grammar files, compiler/ dir, lexer+parser+ast triad) WITHOUT firing on formatters/linters/markdown libs that merely contain a src/parser dir. State the exact conjunction.\n` +
  `2. ecosystem_expansion.go_mod — how Go (go.mod) repos get scanned + classified. What changes in skf-scan-manifests.py.\n` +
  `3. ecosystem_expansion.c_grammar_path — how manifest-LESS C repos (cpython's Grammar/python.gram, ruby's parse.y) get scanned via grammar-file presence, WITHOUT breaking the manifest-first flow that currently hard-halts/falls-interactive on zero manifests. This is the hardest part — be specific about where it slots into the dataflow.\n` +
  `4. interface_change — exact new inputs to skf-shape-detect.py (e.g. --tree-paths/--grammar-files) and how step-auto-scope assembles them.\n` +
  `5. acquisition_change — sparse-checkout glob / tree-fetch changes, their cost, and how they're gated (don't fetch the tree for every repo).\n` +
  `6. files_touched, risks, effort.\n\n` +
  `Be concrete and buildable — reference real file paths from the map. This competes against two other designs; make yours the strongest expression of your stance.`,
  { label: `design:${d.key}`, phase: 'Design', schema: DESIGN_SCHEMA }
))).then(r => r.filter(Boolean))

log(`Generated ${designs.length} competing designs`)

// ---------------------------------------------------------------------------
// Phase 4: Judge panel scores each design
// ---------------------------------------------------------------------------
phase('Score')
const designsBlob = designs.map((d, i) =>
  `## DESIGN ${i + 1}: ${d.name}\n- conjunction: ${d.tier2_conjunction_rule}\n- go.mod: ${d.ecosystem_expansion.go_mod}\n- C/grammar: ${d.ecosystem_expansion.c_grammar_path}\n- interface: ${d.interface_change}\n- acquisition: ${d.acquisition_change || 'n/a'}\n- files: ${(d.files_touched||[]).join(', ')}\n- risks: ${(d.risks||[]).join('; ')}\n- effort: ${d.effort||'n/a'}`
).join('\n\n')

const scores = await parallel(designs.map(d => () => agent(
  `You are an independent reviewer scoring ONE design among three for SKF issue #427 Phase B.\n\n` +
  `## All three designs (for comparison)\n${designsBlob}\n\n` +
  `## Real-repo validation (the coverage bar)\n${validateDigest}\n\n` +
  `## Score THIS design: "${d.name}"\nconjunction: ${d.tier2_conjunction_rule}\ngo.mod: ${d.ecosystem_expansion.go_mod}\nC/grammar: ${d.ecosystem_expansion.c_grammar_path}\ninterface: ${d.interface_change}\nrisks: ${(d.risks||[]).join('; ')}\n\n` +
  `Score 0-10 on: robustness (FP resistance), simplicity (boring/minimal), blast_radius (10=smallest), coverage (how many of rust/TS/cpython/go/ruby it actually catches). Give total (sum) and a sharp rationale. Name the ONE best idea in this design worth grafting into a final synthesis even if this design loses.`,
  { label: `score:${d.name}`.slice(0, 40), phase: 'Score', schema: SCORE_SCHEMA }
))).then(r => r.filter(Boolean))

const ranked = [...scores].sort((a, b) => (b.total || 0) - (a.total || 0))
log(`Scored. Ranking: ${ranked.map(s => `${s.design_name}=${s.total}`).join(', ')}`)

// ---------------------------------------------------------------------------
// Phase 5: Red-team the leading conjunction rule against false-positive repos
// ---------------------------------------------------------------------------
phase('RedTeam')
const leader = designs.find(d => d.name === ranked[0].design_name) || designs[0]
const fpCandidates = [
  'webpack/webpack (bundler with a parser/AST)',
  'postcss/postcss (CSS parser+AST, plugin ecosystem)',
  'prettier/prettier (formatter; parses many languages)',
  'graphql/graphql-js (parses GraphQL, has lexer+parser+ast)',
  'sass/dart-sass (a CSS preprocessor — arguably a language?)',
  'markedjs/marked (markdown lexer+parser)',
]

const redteam = await parallel(fpCandidates.map(c => () => agent(
  `You are red-teaming a proposed classification rule for SKF issue #427. The rule fires "language-reference" (whole-language skill) when:\n\n` +
  `CONJUNCTION RULE: ${leader.tier2_conjunction_rule}\n` +
  `(plus the already-shipped Tier-1: repo's own package name is a known parser-gen tool.)\n\n` +
  `ADVERSARIAL TARGET: ${c}\n\n` +
  `Your goal is to BREAK the rule: does ${c} have a lexer+parser+ast directory triad, a compiler/ dir, or grammar files that would make it WRONGLY fire language-reference? Use deepwiki MCP (ask_question) or web search to check its REAL directory structure — load via ToolSearch "select:mcp__deepwiki__ask_question" if needed. Default to breaks_rule=true if you find a plausible false-positive path. If it genuinely wouldn't fire, say breaks_rule=false and explain what in the rule saves it. Propose a fix that tightens the rule without losing rust/TypeScript/cpython/go/ruby.`,
  { label: `redteam:${c.split('/')[0]}`, phase: 'RedTeam', schema: REDTEAM_SCHEMA }
))).then(r => r.filter(Boolean))

const breaks = redteam.filter(r => r.breaks_rule)
log(`Red-team: ${breaks.length}/${redteam.length} candidates break the leading conjunction rule`)

// ---------------------------------------------------------------------------
// Phase 6: Synthesize the final blueprint
// ---------------------------------------------------------------------------
phase('Synthesize')
const grafts = scores.map(s => `- from ${s.design_name}: ${s.best_idea_to_graft}`).join('\n')
const redteamBlob = redteam.map(r => `- ${r.candidate}: ${r.breaks_rule ? 'BREAKS' : 'safe'} — ${r.why}${r.fix ? ' | FIX: ' + r.fix : ''}`).join('\n')

const blueprint = await agent(
  `You are the lead architect writing the FINAL implementation blueprint for SKF issue #427 Phase B (Tier-2 whole-language detection) + ecosystem expansion. Synthesize — do not just pick one.\n\n` +
  `## Winning design (highest score): ${ranked[0].design_name} (total ${ranked[0].total})\n` +
  `conjunction: ${leader.tier2_conjunction_rule}\ngo.mod: ${leader.ecosystem_expansion.go_mod}\nC/grammar: ${leader.ecosystem_expansion.c_grammar_path}\ninterface: ${leader.interface_change}\nacquisition: ${leader.acquisition_change || 'n/a'}\nfiles: ${(leader.files_touched||[]).join(', ')}\n\n` +
  `## Full ranking\n${ranked.map(s => `${s.design_name}: total=${s.total} (robust=${s.robustness} simple=${s.simplicity} blast=${s.blast_radius} cov=${s.coverage}) — ${s.rationale}`).join('\n')}\n\n` +
  `## Best ideas to graft from each design\n${grafts}\n\n` +
  `## Red-team results on the leading conjunction rule\n${redteamBlob}\n\n` +
  `## Real-repo coverage bar\n${validateDigest}\n\n` +
  `## Architecture seams (ground truth)\n${mapDigest}\n\n` +
  `Produce a single, decisive blueprint as MARKDOWN (not JSON) covering:\n` +
  `1. THE HARDENED CONJUNCTION RULE — incorporating every red-team fix so NONE of the false-positive candidates (webpack/postcss/prettier/graphql-js/dart-sass/marked) wrongly fire, while rust/TypeScript still do. State it precisely enough to code.\n` +
  `2. ECOSYSTEM EXPANSION — go.mod path and the manifest-less C grammar-file path, with exact files to change and how the manifest-less path slots into the dataflow without breaking zero-manifest handling.\n` +
  `3. INTERFACE & ACQUISITION CHANGES — new shape-detect args, sparse-checkout globs, and gating (when do we pay the tree fetch).\n` +
  `4. A SEQUENCED COMMIT PLAN — ordered, each commit small and testable, test-first, with the exact positive controls (rust-lang/rust, TypeScript, cpython, go, ruby) and negative controls (the 6 red-team repos) each commit must satisfy.\n` +
  `5. EXPLICIT RISKS & WHAT TO DEFER if any sub-part proves too large.\n\n` +
  `Be concrete, cite real file paths. This blueprint will be executed directly.`,
  { label: 'synthesize:blueprint', phase: 'Synthesize' }
)

return {
  ranking: ranked.map(s => ({ design: s.design_name, total: s.total })),
  redteam_breaks: breaks.length,
  redteam_total: redteam.length,
  validations: validations.map(v => ({ repo: v.repo, reachable: v.reachable_today, expected: v.expected_classification, signal: v.recommended_signal })),
  blueprint,
}

